do {
                let result = try self.getResult()
                self.forwardOn(.next(result))
            }
            catch let e {
                self.forwardOn(.error(e))
                self.dispose()
            }

var allOthersDone = true

            let arity = self._isDone.count
            for i in 0 ..< arity {
                if i != index && !self._isDone[i] {
                    allOthersDone = false
                    break
                }
            }

            if allOthersDone {
                self.forwardOn(.completed)
                self.dispose()
            }

